/**
 * Identity Fetcher - Transform Sheet Rows to Clean JSON
 * 
 * Expected sheet format (2 columns):
 * | field_name    | field_value              |
 * |---------------|---------------------------|
 * | full_name     | John Doe                  |
 * | email         | john@example.com          |
 * | linkedin_url  | https://linkedin.com/in/j |
 * 
 * Output: Single JSON object with field names as keys
 */

// Get all items from the Google Sheets node
const rows = $input.all();

// Transform rows into a clean key-value object
const userProfile = {};

for (const row of rows) {
  const data = row.json;

  // Handle different possible column names
  const fieldName = data.field_name || data.fieldName || data.Field || data.key || Object.keys(data)[0];
  const fieldValue = data.field_value || data.fieldValue || data.Value || data.value || Object.values(data)[1];

  if (fieldName && fieldValue !== undefined) {
    // Convert field name to snake_case for consistency
    const cleanKey = fieldName
      .toLowerCase()
      .replace(/\s+/g, '_')
      .replace(/[^a-z0-9_]/g, '');

    userProfile[cleanKey] = fieldValue;
  }
}

// Return the clean JSON object
return {
  json: {
    success: true,
    profile: userProfile,
    fetched_at: new Date().toISOString(),
    field_count: Object.keys(userProfile).length
  }
};
